import{_ as o,o as e,c as r,ag as a}from"./chunks/framework.OsDJF_Ea.js";const s="/docs/modules/poly-oscillator.png",g=JSON.parse('{"title":"Poly Oscillator","description":"","frontmatter":{},"headers":[],"relativePath":"modules/poly-oscillator.md","filePath":"modules/poly-oscillator.md"}'),n={name:"modules/poly-oscillator.md"};function d(i,t,l,c,p,u){return e(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="poly-oscillator" tabindex="-1">Poly Oscillator <a class="header-anchor" href="#poly-oscillator" aria-label="Permalink to &quot;Poly Oscillator&quot;">​</a></h1><p><strong>Category:</strong> Sound Sources</p><p>4-to-8 voice polyphonic oscillator with built-in ADSR envelope, stereo spread, voice detuning, and self-contained 2-operator FM synthesis. Accepts MIDI note input for automatic voice allocation with configurable voice stealing. Unison mode stacks all voices on a single pitch for thick leads.</p><img src="'+s+'" alt="poly-oscillator module"><h2 id="inputs" tabindex="-1">Inputs <a class="header-anchor" href="#inputs" aria-label="Permalink to &quot;Inputs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Port</th><th>Description</th></tr></thead><tbody><tr><td><strong>gate</strong></td><td>Manual gate for all voices. Normally driven by the &#39;note&#39; input instead.</td></tr><tr><td><strong>freq</strong></td><td>Raw frequency in Hz applied to all voices. Use instead of &#39;note&#39; for drone or LFO-driven pitch.</td></tr><tr><td><strong>note</strong></td><td>MIDI note input (carries pitch + gate + velocity). Connect from MIDIIn for polyphonic keyboard play.</td></tr><tr><td><strong>detune</strong></td><td>Modulates voice detuning spread in cents. Higher values widen the chorus effect.</td></tr><tr><td><strong>attack</strong></td><td>Modulates ADSR attack time.</td></tr><tr><td><strong>decay</strong></td><td>Modulates ADSR decay time.</td></tr><tr><td><strong>sustain</strong></td><td>Modulates ADSR sustain level 0-1.</td></tr><tr><td><strong>release</strong></td><td>Modulates ADSR release time.</td></tr><tr><td><strong>gain</strong></td><td>Master output amplitude 0-1.</td></tr><tr><td><strong>wt_pos</strong></td><td>Wavetable morph position 0-1. Sweeps through drawn wavetables for timbral animation.</td></tr><tr><td><strong>fm_index</strong></td><td>FM modulation depth. Higher values add more harmonics. Connect an ADSR for percussive FM.</td></tr><tr><td><strong>fm_ratio</strong></td><td>FM carrier-to-modulator frequency ratio. Non-integer values produce inharmonic/bell tones.</td></tr><tr><td><strong>fm_mod_amount</strong></td><td>Attenuator for the fm_index input. Scales how much incoming CV affects FM depth.</td></tr></tbody></table><h2 id="outputs" tabindex="-1">Outputs <a class="header-anchor" href="#outputs" aria-label="Permalink to &quot;Outputs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Port</th><th>Description</th></tr></thead><tbody><tr><td><strong>outL</strong> (audio)</td><td>Left stereo audio. Voices are spread across the stereo field based on stereo_spread param.</td></tr><tr><td><strong>outR</strong> (audio)</td><td>Right stereo audio.</td></tr></tbody></table><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><p>For lush pads: set 8 voices, detune 8-15 cents, stereo spread 0.7, slow attack, long release. Connect MIDIIn &#39;note&#39; output and play chords. Enable FM with low index and ratio of 2.0 for subtle harmonic richness.</p><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h2>',11)])])}const m=o(n,[["render",d]]);export{g as __pageData,m as default};
